class Adder:
    def __init__(self, val):
        self.val = val
    def __call__(self, x):
        return self.val + x

add_five = Adder(5)
print(add_five(10))

class Counter:
    def __init__(self):
        self.count = 0
    def __call__(self):
        self.count += 1
        return self.count

Counter()()
print(Counter()())

