challenge.solution:
class Cache:
  def __init__(self, func):
    self.func = func
    self.cache = {}

  def __call__(self, arg):
    if arg not in self.cache:
      self.cache[arg] = self.func(arg)
    return self.cache[arg]

def slow_square(n):
  return n * n

cached_square = Cache(slow_square)
print(cached_square(4))
print(cached_square(4))
